import { createLinterRuleTester, expectDiagnostics, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { callsGraphRule } from "../rules/calls-graph.rule.js";

// a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_calls
describe("@calls", () => {
  // T013_01: @tool(#{ sequential: false }) @calls([fetch_context]) op inside @component Agent — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_01
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_calls:Products.A10nBlueprintEngine.Features.CallsWhitelist.tool_calls:must
  it("T013_01: @tool(#{ sequential: false }) @calls([sdk_op]) inside @component Agent — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Sdk })
      namespace Components.ContextSdk {
        @operation(#{})
        op fetch_context(pr_url: string): string;
      }

      @component(#{
        type: ComponentType.Agent,
      })
      @dependsOn([Components.ContextSdk])
      namespace Components.MyAgent {
        @tool(#{ sequential: false })
        @calls([Components.ContextSdk.fetch_context])
        op summarize_pr(): void;
      }
    `);
  });

  // T013_02: @operation @calls([validate_input, persist_record]) inside @component Service — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_02
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_calls:Products.A10nBlueprintEngine.Features.CallsWhitelist.protocol_entry_calls:must
  it("T013_02: http_op @calls sdk ops inside @component Service — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Sdk })
      namespace Components.ValidationSdk {
        @operation(#{})
        op validate_input(data: string): boolean;
        @operation(#{})
        op persist_record(data: string): void;
      }

      @component(#{
        type: ComponentType.Service,
      })
      @dependsOn([Components.ValidationSdk])
      namespace Components.MyApiService {
        namespace Http {
          @calls([Components.ValidationSdk.validate_input, Components.ValidationSdk.persist_record])
          op create_task(): void;
        }
      }
    `);
  });

  // T013_03: @calls on a model — TypeSpec extern dec rejects model target (decorator-wrong-target)
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_03
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_calls:Products.A10nBlueprintEngine.Features.OperationCallGraph.calls_op_only:must
  it("T013_03: @calls on model — TypeSpec extern dec rejects non-operation target", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{
        type: ComponentType.Agent,
      })
      namespace Components.MyAgent {
        op some_op(): void;

        @calls([Components.MyAgent.some_op])
        model TaskRow { id: string; }
      }
    `);
    // TypeSpec enforces the extern dec target constraint
    expectDiagnostics(diagnostics, {
      code: "decorator-wrong-target",
    });
  });

  // T013_04: @calls with a Model as target — TypeSpec type checker rejects it with invalid-argument
  // (Model is not assignable to Operation[] parameter type)
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_04
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_calls:Products.A10nBlueprintEngine.Features.OperationCallGraph.calls_target_op:must
  it("T013_04: @calls([SomeModel]) — TypeSpec type checker rejects non-operation arg", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{
        type: ComponentType.Agent,
      })
      namespace Components.MyAgent {
        model SomeModel { id: string; }

        @tool(#{ sequential: false })
        @calls([Components.MyAgent.SomeModel])
        op summarize_pr(): void;
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "invalid-argument",
    });
  });

  // T013_05: @calls(["fetch_context"]) string literal — TypeSpec rejects non-op arg
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_05
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_calls:Products.A10nBlueprintEngine.Features.OperationCallGraph.targets_typed:must
  it("T013_05: @calls with string literal — TypeSpec rejects invalid-argument", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{
        type: ComponentType.Agent,
      })
      namespace Components.MyAgent {
        @tool(#{ sequential: false })
        @calls(["fetch_context"])
        op summarize_pr(): void;
      }
    `);
    expectDiagnostics(diagnostics, [
      { code: "invalid-argument" },
    ]);
  });

  // T013_07: @tool(#{ sequential: false }) op with no @calls compiles — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_07
  it("T013_07: @tool(#{ sequential: false }) op with no @calls — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{
        type: ComponentType.Agent,
      })
      namespace Components.MyAgent {
        @tool(#{ sequential: false })
        op summarize_pr(): void;
      }
    `);
  });

  // T013_09: @tool(#{ sequential: false }) @calls([op_a, op_b]) inside component — zero diagnostics (complete list)
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_09
  it("T013_09: @tool(#{ sequential: false }) @calls([sdk_op_a, sdk_op_b]) inside component — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Sdk })
      namespace Components.HelperSdk {
        @operation(#{})
        op op_a(): void;
        @operation(#{})
        op op_b(): void;
      }

      @component(#{
        type: ComponentType.Agent,
      })
      @dependsOn([Components.HelperSdk])
      namespace Components.MyAgent {
        @tool(#{ sequential: false })
        @calls([Components.HelperSdk.op_a, Components.HelperSdk.op_b])
        op summarize_pr(): void;
      }
    `);
  });

  // T013_11: @tool(#{ sequential: false }) @calls([SomeService.do_work]) with @dependsOn([SomeService]) — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_11
  it("T013_11: @tool @calls http_op in peer Service — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      namespace Components {
        @component(#{
          type: ComponentType.Service,
        })
        namespace SomeService {
          namespace Http {
            op do_work(): void;
          }
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.SomeService])
        namespace MyAgent {
          @tool(#{ sequential: false })
          @calls([Components.SomeService.Http.do_work])
          op summarize_pr(): void;
        }
      }
    `);
  });

  // T013_12: typed reference @calls([Components.OtherService.fetch_data]) — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_12
  it("T013_12: @tool typed reference @calls http_op — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      namespace Components {
        @component(#{
          type: ComponentType.Service,
        })
        namespace OtherService {
          namespace Http {
            op fetch_data(): void;
          }
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.OtherService])
        namespace MyAgent {
          @tool(#{ sequential: false })
          @calls([Components.OtherService.Http.fetch_data])
          op summarize_pr(): void;
        }
      }
    `);
  });

  // T013_14: sdk_op @calls another sdk_op cross-boundary — zero diagnostics
  // (sdk_op_calls invariant: sdk_op may @calls cross_boundary callees only)
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_14
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_calls:Products.A10nBlueprintEngine.Features.CallsWhitelist.sdk_op_calls:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_reads:Products.A10nBlueprintEngine.Features.CallsWhitelist.sdk_op_calls:must
  it("T013_14: sdk_op @calls peer sdk_op (cross_boundary) — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Sdk })
      namespace Components.PeerSdk {
        @operation(#{})
        op helper(): void;
      }

      @component(#{ type: ComponentType.Sdk })
      @dependsOn([Components.PeerSdk])
      namespace Components.MySdk {
        @operation(#{})
        @calls([Components.PeerSdk.helper])
        op my_op(): void;
      }
    `);
  });

  // T013_15: sdk_op @calls a graph node (not cross_boundary) — diagnostic
  // (sdk_op_calls invariant: callee must be cross_boundary, so a non-entry graph_node is rejected)
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_15
  it("T013_15: sdk_op @calls a non-entry graph node — calls-invalid-caller-callee fires", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{ type: ComponentType.Agent })
      namespace Components.MyAgent {
        @graph
        namespace Graph {
          @node(#{ is_entrypoint: false })
          op inner_node(): void;
        }
      }

      @component(#{ type: ComponentType.Sdk })
      @dependsOn([Components.MyAgent])
      namespace Components.MySdk {
        @operation(#{})
        @calls([Components.MyAgent.Graph.inner_node])
        op my_op(): void;
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/calls-invalid-caller-callee",
    });
  });

  // T013_16: probabilistic @signal @calls a predict_op — zero diagnostics
  // (probabilistic_signal_calls invariant: probabilistic signal may only @calls predict_op)
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_16
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_calls:Products.A10nBlueprintEngine.Features.CallsWhitelist.probabilistic_signal_calls:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_reads:Products.A10nBlueprintEngine.Features.CallsWhitelist.probabilistic_signal_calls:must
  it("T013_16: probabilistic @signal @calls a @predict op — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Agent })
      namespace Components.MyAgent {
        model PredictOut { label: string; }

        @graph
        namespace Graph {
          @predict op my_predict(input: string): PredictOut;
        }

        @eval(#{ title: "Eval one" })
        namespace Evals.MyFeature.E001 {
          @signal(#{
            title: "Comment actionable",
            method: SignalMethod.Probabilistic,
            criteria: "Does it suggest a fix?",
            examples: #[]
          })
          @calls([Components.MyAgent.Graph.my_predict])
          op E001_01(): boolean;
        }
      }
    `);
  });

  // T013_17: probabilistic @signal @calls a non-predict op — diagnostic
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_17
  it("T013_17: probabilistic @signal @calls a non-predict (sdk_op) target — calls-invalid-caller-callee fires", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{ type: ComponentType.Sdk })
      namespace Components.HelperSdk {
        @operation(#{})
        op helper(): void;
      }

      @component(#{ type: ComponentType.Agent })
      @dependsOn([Components.HelperSdk])
      namespace Components.MyAgent {
        @eval(#{ title: "Eval one" })
        namespace Evals.MyFeature.E001 {
          @signal(#{
            title: "Comment actionable",
            method: SignalMethod.Probabilistic,
            criteria: "Does it suggest a fix?",
            examples: #[]
          })
          @calls([Components.HelperSdk.helper])
          op E001_01(): boolean;
        }
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/calls-invalid-caller-callee",
    });
  });

  // T013_13: @calls([fetch_context]) with @doc describing outcome not callees — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_13
  it("T013_13: @tool @calls sdk_op + @doc describing outcome (not callee) — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Sdk })
      namespace Components.ContextSdk {
        @operation(#{})
        op fetch_context(pr_url: string): string;
      }

      @component(#{
        type: ComponentType.Agent,
      })
      @dependsOn([Components.ContextSdk])
      namespace Components.MyAgent {
        @doc("Produces a concise summary of the pull request")
        @tool(#{ sequential: false })
        @calls([Components.ContextSdk.fetch_context])
        op summarize_pr(): void;
      }
    `);
  });

  // Callable nested dependency-component ops. A first-party cli_op @calls an op
  // hosted under Dependencies.<Dep>.Components.<Name>.…  The classifier
  // (classifyCallee) keys off the nearest @component decorator type, so a dep
  // SERVICE op under Http and a dep LIBRARY op under Sdk.Operations both
  // classify as cross_boundary — zero calls-invalid-caller-callee diagnostics.
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_calls:Products.A10nBlueprintEngine.Features.CallsWhitelist.protocol_entry_calls:must
  it("T013_14: first-party cli_op @calls a dep SERVICE op at Dependencies.Acme.Components.AcmeService.Http.get — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @dependency(#{
        title: "Acme",
        type: DependencyType.Service,
        status: DependencyStatus.Active,
        sources: #[]
      })
      namespace Dependencies.Acme {}

      @component(#{ type: ComponentType.Service })
      namespace Dependencies.Acme.Components.AcmeService {
        namespace Http {
          @operation(#{})
          op get(id: string): string;
        }
      }

      @component(#{ type: ComponentType.Service })
      @dependsOn([Dependencies.Acme.Components.AcmeService])
      @testing(Dependencies.Acme.Components.AcmeService, #{ approach: TestingApproach.Mock, reasoning: "test fixture" })
      namespace Components.MyCliService {
        namespace Commands {
          namespace Run {
            @doc("Runs the thing")
            @operation(#{})
            @calls([Dependencies.Acme.Components.AcmeService.Http.get])
            op run(): void;
          }
        }
      }
    `);
  });

  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_calls:Products.A10nBlueprintEngine.Features.CallsWhitelist.protocol_entry_calls:must
  it("T013_15: first-party cli_op @calls a dep LIBRARY op at Dependencies.Acme.Components.AcmeSdk.Operations.fetch — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @dependency(#{
        title: "Acme",
        type: DependencyType.Library,
        status: DependencyStatus.Active,
        sources: #[]
      })
      namespace Dependencies.Acme {}

      @component(#{ type: ComponentType.Sdk })
      namespace Dependencies.Acme.Components.AcmeSdk {
        namespace Operations {
          @operation(#{})
          op fetch(id: string): string;
        }
      }

      @component(#{ type: ComponentType.Service })
      @dependsOn([Dependencies.Acme.Components.AcmeSdk])
      @testing(Dependencies.Acme.Components.AcmeSdk, #{ approach: TestingApproach.Mock, reasoning: "test fixture" })
      namespace Components.MyCliService {
        namespace Commands {
          namespace Run {
            @doc("Runs the thing")
            @operation(#{})
            @calls([Dependencies.Acme.Components.AcmeSdk.Operations.fetch])
            op run(): void;
          }
        }
      }
    `);
  });
});

// T013_08: @calls + @doc with target name — calls-graph rule fires
describe("@calls doc-omits-facts rule (T013_08)", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, callsGraphRule, "@a10n/blueprint-typespec");
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T013.T013_08
  it("T013_08: @calls + @doc containing {@ref} to callee — fires calls-graph", async () => {
    await ruleTester
      .expect(`
        @component(#{ type: ComponentType.Sdk })
        namespace Components.ContextSdk {
          @operation(#{})
          op fetch_context(pr_url: string): string;
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.ContextSdk])
        @testing(Components.ContextSdk, #{ approach: TestingApproach.Mock, reasoning: "test fixture" })
        namespace Components.MyAgent {
          @doc("Invokes {\\@Components.ContextSdk.fetch_context} to gather context")
          @tool(#{ sequential: false })
          @calls([Components.ContextSdk.fetch_context])
          op summarize_pr(): void;
        }
      `)
      .toEmitDiagnostics({
        code: "@a10n/blueprint-typespec/calls-graph",
        message: /summarize_pr/,
      });
  });

  it("T013_08b: @calls + @doc not mentioning the callee — no diagnostic", async () => {
    await ruleTester
      .expect(`
        @component(#{ type: ComponentType.Sdk })
        namespace Components.ContextSdk {
          @operation(#{})
          op fetch_context(pr_url: string): string;
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.ContextSdk])
        @testing(Components.ContextSdk, #{ approach: TestingApproach.Mock, reasoning: "test fixture" })
        namespace Components.MyAgent {
          @doc("Summarizes a pull request")
          @tool(#{ sequential: false })
          @calls([Components.ContextSdk.fetch_context])
          op summarize_pr(): void;
        }
      `)
      .toBeValid();
  });
});
